"""sklearn.feature_selection — Univariate feature selection."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


# ---------- scoring functions ----------

def f_classif(X, y):
    """ANOVA F-value for classification."""
    X, y = np.asarray(X, dtype=float), np.asarray(y)
    classes = np.unique(y)
    n_samples, n_features = X.shape
    grand_mean = X.mean(axis=0)
    ss_between = np.zeros(n_features)
    ss_within = np.zeros(n_features)
    for c in classes:
        Xc = X[y == c]
        nc = Xc.shape[0]
        class_mean = Xc.mean(axis=0)
        ss_between += nc * (class_mean - grand_mean) ** 2
        ss_within += np.sum((Xc - class_mean) ** 2, axis=0)
    k = len(classes)
    df_between = k - 1
    df_within = n_samples - k
    ms_between = ss_between / max(df_between, 1)
    ms_within = ss_within / max(df_within, 1)
    f_stat = ms_between / (ms_within + 1e-15)
    # p-values approximation (not exact without scipy, return f_stat as proxy)
    p_values = 1.0 / (1.0 + f_stat)
    return f_stat, p_values


def f_regression(X, y):
    """F-value for univariate linear regression."""
    X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
    n = X.shape[0]
    y_mean = y.mean()
    corr = np.array([np.corrcoef(X[:, j], y)[0, 1] for j in range(X.shape[1])])
    corr = np.nan_to_num(corr)
    df = max(n - 2, 1)
    f_stat = corr ** 2 / (1 - corr ** 2 + 1e-15) * df
    p_values = 1.0 / (1.0 + f_stat)
    return f_stat, p_values


def chi2(X, y):
    """Chi-squared stats for non-negative features and classification."""
    X, y = np.asarray(X, dtype=float), np.asarray(y)
    classes = np.unique(y)
    observed = np.array([X[y == c].sum(axis=0) for c in classes])  # (k, p)
    feature_totals = X.sum(axis=0)
    class_totals = observed.sum(axis=1)
    n_total = X.sum()
    expected = np.outer(class_totals, feature_totals) / (n_total + 1e-15)
    chi2_stat = np.sum((observed - expected) ** 2 / (expected + 1e-15), axis=0)
    p_values = 1.0 / (1.0 + chi2_stat)
    return chi2_stat, p_values


def mutual_info_classif(X, y, n_neighbors=3, random_state=None):
    """Estimated mutual information for discrete targets (simplified).

    Uses a binning approach as a lightweight approximation.
    """
    X, y = np.asarray(X, dtype=float), np.asarray(y)
    n_features = X.shape[1]
    mi = np.zeros(n_features)
    classes = np.unique(y)
    n = len(y)
    for j in range(n_features):
        # Discretise feature into 10 bins
        bins = np.linspace(X[:, j].min() - 1e-8, X[:, j].max() + 1e-8, 11)
        x_binned = np.digitize(X[:, j], bins)
        x_vals = np.unique(x_binned)
        for xv in x_vals:
            px = np.mean(x_binned == xv)
            for c in classes:
                py = np.mean(y == c)
                pxy = np.mean((x_binned == xv) & (y == c))
                if pxy > 0:
                    mi[j] += pxy * np.log(pxy / (px * py + 1e-15) + 1e-15)
    mi = np.maximum(mi, 0)
    return mi


# ---------- selectors ----------

class VarianceThreshold(BaseEstimator, TransformerMixin):
    """Feature selector removing low-variance features.

    Parameters
    ----------
    threshold : float, default=0.0
    """

    def __init__(self, threshold=0.0):
        self.threshold = threshold

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        self.variances_ = np.var(X, axis=0)
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        mask = self.variances_ > self.threshold
        return X[:, mask]

    def get_support(self):
        return self.variances_ > self.threshold


class SelectKBest(BaseEstimator, TransformerMixin):
    """Select features according to the k highest scores.

    Parameters
    ----------
    score_func : callable, default=f_classif
    k : int, default=10
    """

    def __init__(self, score_func=None, k=10):
        self.score_func = score_func or f_classif
        self.k = k

    def fit(self, X, y):
        self.scores_, self.pvalues_ = self.score_func(np.asarray(X, dtype=float), np.asarray(y))
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        mask = self.get_support()
        return X[:, mask]

    def get_support(self):
        k = min(self.k, len(self.scores_))
        idx = np.argsort(self.scores_)[::-1][:k]
        mask = np.zeros(len(self.scores_), dtype=bool)
        mask[idx] = True
        return mask


class SelectPercentile(BaseEstimator, TransformerMixin):
    """Select features according to a percentile of the highest scores.

    Parameters
    ----------
    score_func : callable, default=f_classif
    percentile : int, default=10
    """

    def __init__(self, score_func=None, percentile=10):
        self.score_func = score_func or f_classif
        self.percentile = percentile

    def fit(self, X, y):
        self.scores_, self.pvalues_ = self.score_func(np.asarray(X, dtype=float), np.asarray(y))
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        mask = self.get_support()
        return X[:, mask]

    def get_support(self):
        threshold = np.percentile(self.scores_, 100 - self.percentile)
        return self.scores_ >= threshold
